<?php require_once 'config/db.php'; require_once 'includes/auth.php'; $error=''; $success=''; if($_SERVER['REQUEST_METHOD']==='POST'){ $u=trim($_POST['username']); $n=trim($_POST['full_name']); $e=trim($_POST['email']); $p=$_POST['password']; if(strlen($p)<6)$error='Password must be at least 6 characters.'; else{ $hash=password_hash($p,PASSWORD_DEFAULT); $role='user'; $stmt=mysqli_prepare($conn,'INSERT INTO APP_USER(username,full_name,email,password_hash,role) VALUES(?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'sssss',$u,$n,$e,$hash,$role); if(mysqli_stmt_execute($stmt))$success='Account created. You can login now.'; else $error='Username or email already exists.'; }} ?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Signup</title><link rel="stylesheet" href="assets/css/style.css"></head><body class="auth-body"><form class="auth-card" method="POST"><h1>User Sign Up</h1><p>Create normal user account.</p><?php if($error): ?><div class="alert alert-error"><?= safe($error) ?></div><?php endif; ?><?php if($success): ?><div class="alert alert-success"><?= safe($success) ?></div><?php endif; ?><label>Username</label><input class="input" name="username" required><label>Full Name</label><input class="input" name="full_name" required><label>Email</label><input class="input" type="email" name="email" required><label>Password</label><input class="input" type="password" name="password" required><button class="btn">Sign Up</button> <a class="btn btn-light" href="index.php">Back</a></form></body></html>
